async def vote_useful(
    slug: str,
    user: User = Depends(get_current_user),
    db: AsyncSession = Depends(get_db),
):
    result = await db.execute(select(Tool).where(Tool.slug == slug, Tool.is_active == True))
    tool = result.scalar_one_or_none()
    if not tool:
        raise HTTPException(status_code=404, detail="Tool not found")

    existing = await db.execute(
        select(ToolVote).where(ToolVote.tool_id == tool.id, ToolVote.user_id == user.id)
    )
    if existing.scalar_one_or_none():
        return {"status": "already_voted"}

    db.add(ToolVote(tool_id=tool.id, user_id=user.id))
    await db.commit()

    count = (await db.execute(select(func.count()).where(ToolVote.tool_id == tool.id))).scalar()
    return {"status": "voted", "vote_count": count}

async def remove_vote(
    slug: str,
    user: User = Depends(get_current_user),
    db: AsyncSession = Depends(get_db),
):
    result = await db.execute(select(Tool).where(Tool.slug == slug, Tool.is_active == True))
    tool = result.scalar_one_or_none()
    if not tool:
        raise HTTPException(status_code=404, detail="Tool not found")

    existing = await db.execute(
        select(ToolVote).where(ToolVote.tool_id == tool.id, ToolVote.user_id == user.id)
    )
    vote = existing.scalar_one_or_none()
    if not vote:
        return {"status": "not_voted"}

    await db.delete(vote)
    await db.commit()

    count = (await db.execute(select(func.count()).where(ToolVote.tool_id == tool.id))).scalar()
    return {"status": "removed", "vote_count": count}

async def get_embedding(text_input: str) -> list[float] | None:
    if not settings.gemini_api_key:
        return None
    try:
        from google import genai

        client = genai.Client(api_key=settings.gemini_api_key)
        result = client.models.embed_content(
            model="models/gemini-embedding-001",
            contents=text_input,
        )
        return result.embeddings[0].values
    except Exception:
        return None

async def list_categories(db: AsyncSession = Depends(get_db)):
    result = await db.execute(
        select(ForumCategory).order_by(ForumCategory.sort_order)
    )
    categories = result.scalars().all()

    out = []
    for cat in categories:
        thread_count = (await db.execute(
            select(func.count()).where(ForumThread.category_id == cat.id)
        )).scalar()
        out.append({
            "slug": cat.slug,
            "name": cat.name,
            "description": cat.description,
            "thread_count": thread_count,
        })
    return {"categories": out}

def _iso(dt: datetime) -> str:
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt.isoformat()

async def update_profile(
    body: UpdateProfile,
    user: User = Depends(get_current_user),
    db: AsyncSession = Depends(get_db),
):
    if body.display_name is not None:
        user.display_name = body.display_name
    if body.bio is not None:
        user.bio = body.bio
    await db.commit()
    return {"status": "updated"}

def slugify(name: str) -> str:
    slug = re.sub(r"[^a-z0-9]+", "-", name.lower()).strip("-")
    return slug

async def update_tool(
    slug: str,
    body: ToolUpdate,
    user: User = Depends(get_current_user),
    db: AsyncSession = Depends(get_db),
):
    result = await db.execute(select(Tool).where(Tool.slug == slug, Tool.is_active == True))
    tool = result.scalar_one_or_none()
    if not tool:
        raise HTTPException(status_code=404, detail="Tool not found")
    if tool.author_id != user.id:
        raise HTTPException(status_code=403, detail="Not the owner")

    if body.description is not None:
        tool.description = body.description
    if body.problem_statement is not None:
        tool.problem_statement = body.problem_statement
    if body.repo_url is not None:
        tool.repo_url = body.repo_url
    if body.language is not None:
        tool.language = body.language
    if body.tags is not None:
        await db.execute(
            ToolTag.__table__.delete().where(ToolTag.tool_id == tool.id)
        )
        for tag_name in body.tags[:20]:
            db.add(ToolTag(tool_id=tool.id, tag=tag_name.lower().strip()))

    await db.commit()

    # Re-scan proximity if problem statement changed
    if body.problem_statement is not None:
        try:
            await scan_proximity(tool, db)
        except Exception as e:
            import logging
            logging.error(f"Proximity scan failed for {tool.slug}: {e}")

    return {"slug": tool.slug, "status": "updated"}

def must_be_mit(cls, v: str) -> str:
    if v.upper() != "MIT":
        raise ValueError(
            "centaur.tools requires MIT license. "
            "The social contract is: everything forkable, stealable, buildable-upon. "
            "Cite your parents. MIT is the only license that guarantees this."
        )
    return "MIT"

async def unread_count(
    user: User = Depends(get_current_user),
    db: AsyncSession = Depends(get_db),
):
    count = (await db.execute(
        select(func.count()).where(
            Notification.user_id == user.id,
            Notification.read == False,
        )
    )).scalar()
    return {"count": count}
